import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.Codec;

public class XSSProtectedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Protected Page</title></head>");
        out.println("<body>");

        // Properly handle user input with ESAPI encoding
        Codec codec = ESAPI.encoder();
        String safeUserInput = codec.encodeForHTML(userInput);

        out.println("User Input: " + safeUserInput);

        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
